 NS_state = false;
 return;
 }
 int current_sec = timeinfo->tm_hour * 3600 + timeinfo->tm_min * 60 + timeinfo->tm_sec;
 if (T11_NIGHT_TIME_START < T12_NIGHT_TIME_END) {
 NS_state = (current_sec > T11_NIGHT_TIME_START) && (current_sec < T12_NIGHT_TIME_END);
 if (NS_state) {
 NS_lastUpdateTime = millis() + (T12_NIGHT_TIME_END - current_sec) * 1000UL - NS_Interval;
 } else {
 if (current_sec < T11_NIGHT_TIME_START) {
 NS_lastUpdateTime = millis() + (T11_NIGHT_TIME_START - current_sec) * 1000UL - NS_Interval;
 } else if (current_sec > T12_NIGHT_TIME_END) {
 NS_lastUpdateTime = millis() + (86400 - current_sec + T11_NIGHT_TIME_START) * 1000UL - NS_Interval;
 }
 }
 } else {
 NS_state = current_sec > T11_NIGHT_TIME_START || current_sec < T12_NIGHT_TIME_END;
 if (NS_state) {
 if (current_sec > T11_NIGHT_TIME_START) {
 NS_lastUpdateTime = millis() + (86400 - current_sec + T12_NIGHT_TIME_END) * 1000UL - NS_Interval;
 } else if (current_sec < T12_NIGHT_TIME_END) {
 NS_lastUpdateTime = millis() + (T12_NIGHT_TIME_END - current_sec) * 1000UL - NS_Interval;
 }
